package com.promonts.dto;import com.promonts.domain.course.Course;import lombok.*;@Data @NoArgsConstructor @AllArgsConstructor @Builder public class CourseListResponse{private Long id;private String name;private String code;private String professorName;private String semester;private Integer year;public static CourseListResponse from(Course course){return CourseListResponse.builder().id(course.getId()).name(course.getName()).code(course.getCode()).professorName(course.getProfessor().getName()).semester(course.getSemester()).year(course.getYear()).build();}}
